import{_ as i,o as a,c as n,ag as o}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"ADR: Frontend Supply-Chain Security Model","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-frontend-supply-chain-security.md","filePath":"adr/ADR-frontend-supply-chain-security.md","lastUpdated":1775910991000}'),t={name:"adr/ADR-frontend-supply-chain-security.md"};function l(r,e,s,c,d,p){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-frontend-supply-chain-security-model" tabindex="-1">ADR: Frontend Supply-Chain Security Model <a class="header-anchor" href="#adr-frontend-supply-chain-security-model" aria-label="Permalink to &quot;ADR: Frontend Supply-Chain Security Model&quot;">​</a></h1><p><strong>Date:</strong> 2026-04-11 <strong>Status:</strong> Accepted <strong>Risk tier:</strong> architectural</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RustChat&#39;s frontend is a Vue 3 SPA with a standard JavaScript dependency graph and build pipeline. The current baseline already has some good properties:</p><ol><li>The active frontend CI path uses <code>npm ci</code> and a committed <code>frontend/package-lock.json</code>.</li><li>The app already ships an internal fetch-based HTTP client in <a href="../../frontend/src/api/http/HttpClient.ts">frontend/src/api/http/HttpClient.ts</a>.</li><li>The current branch is already removing the stale <code>frontend/pnpm-lock.yaml</code>, signaling package-manager normalization toward npm.</li></ol><p>But several supply-chain gaps remain:</p><ol><li>CI still allows package lifecycle scripts during dependency installation.</li><li>PRs do not have automated dependency review or direct-dependency policy enforcement.</li><li>The frontend Docker build still falls back to unlocked <code>npm install</code>.</li><li>Vulnerability scanning and machine-readable dependency inventory are not enforced in frontend CI.</li><li>Remaining raw <code>fetch()</code> call sites in theme preference code bypass the internal HTTP boundary.</li><li>Some direct dependencies appear unused and still expand the review and remediation surface.</li></ol><p>This ADR establishes a security model that reduces attack surface without rewriting the Vue stack or adding dependency-management tools just to manage dependencies.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="_1-package-manager-choice-npm" tabindex="-1">1. Package manager choice: npm <a class="header-anchor" href="#_1-package-manager-choice-npm" aria-label="Permalink to &quot;1. Package manager choice: npm&quot;">​</a></h3><p>RustChat will standardize the frontend on <strong>npm</strong> with <strong>one committed lockfile</strong>: <code>frontend/package-lock.json</code>.</p><p>Reasons:</p><ol><li>npm is already the active package manager in frontend CI, contributor docs, and Docker build flow.</li><li>The current branch is already converging away from <code>pnpm-lock.yaml</code>.</li><li>npm provides the features required for this hardening effort: <ul><li>deterministic <code>npm ci</code></li><li><code>overrides</code> for transitive version control</li><li>built-in audit support</li><li>machine-readable dependency tree generation</li></ul></li><li>Staying on npm avoids introducing a package-manager migration during a security hardening task whose goal is reduced surprise and smaller operational burden.</li></ol><h3 id="_2-lockfile-enforcement-approach" tabindex="-1">2. Lockfile enforcement approach <a class="header-anchor" href="#_2-lockfile-enforcement-approach" aria-label="Permalink to &quot;2. Lockfile enforcement approach&quot;">​</a></h3><p>Frontend installs in CI and release-oriented build paths will use <strong>lockfile-only installs</strong>:</p><ol><li>CI uses <code>npm ci --ignore-scripts</code>.</li><li>The frontend Docker build uses <code>npm ci --ignore-scripts</code>.</li><li><code>frontend/package-lock.json</code> is the single source of truth for resolved frontend dependencies.</li><li>Additional lockfiles such as <code>pnpm-lock.yaml</code> and <code>yarn.lock</code> are forbidden in the frontend workspace.</li><li>A repo-owned policy script validates that <code>package.json</code> and <code>package-lock.json</code> stay synchronized.</li></ol><h3 id="_3-ci-install-policy" tabindex="-1">3. CI install policy <a class="header-anchor" href="#_3-ci-install-policy" aria-label="Permalink to &quot;3. CI install policy&quot;">​</a></h3><p>Frontend CI will enforce a <strong>hardened install pipeline</strong>:</p><ol><li>install from lockfile only</li><li>block lifecycle scripts by default</li><li>apply only trusted, repo-owned dependency patches after install if configured</li><li>run dependency policy validation</li><li>run vulnerability scanning</li><li>run unit tests and build only after the hardened dependency phase passes</li></ol><h3 id="_4-lifecycle-script-policy" tabindex="-1">4. Lifecycle script policy <a class="header-anchor" href="#_4-lifecycle-script-policy" aria-label="Permalink to &quot;4. Lifecycle script policy&quot;">​</a></h3><p>Lifecycle scripts are <strong>blocked in CI by default</strong> and remain <strong>allowed locally</strong>.</p><p>Decision:</p><ol><li>CI-only script blocking is the default and enforced path.</li><li>Local development keeps standard npm behavior to avoid surprising contributors and to preserve normal package workflows.</li><li>If a tool needs post-install behavior in CI, that behavior must be invoked as an explicit trusted step after install, not as an implicit dependency lifecycle hook.</li></ol><p>Example:</p><ol><li>Playwright browser binaries are installed via explicit <code>npx playwright install chromium</code> in CI after dependency installation, not through dependency lifecycle execution.</li></ol><h3 id="_5-dependency-review-tooling" tabindex="-1">5. Dependency review tooling <a class="header-anchor" href="#_5-dependency-review-tooling" aria-label="Permalink to &quot;5. Dependency review tooling&quot;">​</a></h3><p>Frontend dependency changes are governed by <strong>three layers</strong>:</p><ol><li><strong>GitHub dependency review</strong> on pull requests for package and lockfile deltas.</li><li><strong>Repo-owned dependency policy validation</strong> against a machine-readable allowlist in <code>frontend/dependency-policy.json</code>.</li><li><strong><code>npm audit</code> high-severity gate</strong> in frontend CI.</li></ol><p>This combination makes dependency changes:</p><ol><li>visible in PRs</li><li>attributable to an approved category and rationale</li><li>blocked when high-severity vulnerabilities are introduced</li></ol><h3 id="_6-override-and-patch-mechanism" tabindex="-1">6. Override and patch mechanism <a class="header-anchor" href="#_6-override-and-patch-mechanism" aria-label="Permalink to &quot;6. Override and patch mechanism&quot;">​</a></h3><p>RustChat will use a <strong>two-step transitive remediation model</strong>:</p><ol><li><strong><code>package.json</code> <code>overrides</code> first</strong><ul><li>lowest-friction path</li><li>works well when a safe transitive version can be forced centrally</li></ul></li><li><strong>repo-managed patch manifest second</strong><ul><li>used when version forcing is insufficient</li><li>patches are stored in <code>frontend/patches/</code></li><li>patch metadata is stored in <code>frontend/dependency-patches.json</code></li><li>patches are applied by a trusted repo script after install</li></ul></li></ol><p>This avoids adding a new package like <code>patch-package</code> just to patch dependencies.</p><h3 id="_7-update-automation-policy" tabindex="-1">7. Update automation policy <a class="header-anchor" href="#_7-update-automation-policy" aria-label="Permalink to &quot;7. Update automation policy&quot;">​</a></h3><p>Frontend dependency updates will be <strong>PR-based and reviewable</strong>:</p><ol><li>Dependabot manages frontend npm update PRs.</li><li>Minor and patch updates may be grouped for review efficiency.</li><li>Major version updates are not auto-grouped for routine rollout and are never auto-merged by policy.</li><li>Security updates remain distinct from ordinary feature/tooling upgrades and must still pass the same CI gates.</li></ol><h3 id="_8-http-layer-decision-internal-fetch-wrapper-over-third-party-client" tabindex="-1">8. HTTP layer decision: internal fetch wrapper over third-party client <a class="header-anchor" href="#_8-http-layer-decision-internal-fetch-wrapper-over-third-party-client" aria-label="Permalink to &quot;8. HTTP layer decision: internal fetch wrapper over third-party client&quot;">​</a></h3><p>RustChat will keep the existing <strong>internal fetch-based HTTP client</strong> and migrate remaining raw preference-related <code>fetch()</code> calls behind internal APIs where practical.</p><p>Decision:</p><ol><li>Do not add or reintroduce a third-party HTTP client.</li><li>Reuse the existing internal client and centralized error/auth handling.</li><li>Keep external package access behind internal application boundaries where reasonable.</li></ol><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><h3 id="npm-vs-pnpm" tabindex="-1">npm vs pnpm <a class="header-anchor" href="#npm-vs-pnpm" aria-label="Permalink to &quot;npm vs pnpm&quot;">​</a></h3><p><strong>npm</strong></p><p>Pros:</p><ol><li>already active in CI, Docker, and contributor docs</li><li>no migration cost during hardening</li><li>sufficient support for lockfile enforcement, overrides, audit, and inventory generation</li></ol><p>Cons:</p><ol><li>weaker store isolation than pnpm</li><li>historically more permissive defaults unless CI is hardened explicitly</li></ol><p><strong>pnpm</strong></p><p>Pros:</p><ol><li>excellent disk deduplication and stricter node_modules layout</li><li>strong support for patching and overrides</li></ol><p>Cons:</p><ol><li>would require a package-manager migration during a security hardening task</li><li>would increase contributor surprise because the repo already runs npm in CI</li><li>would re-open workflow normalization work that the current branch is already resolving in the opposite direction</li></ol><p>Decision:</p><ol><li>Choose <strong>npm</strong> because contributor clarity and low migration risk matter more here than pnpm&#39;s structural advantages.</li></ol><h3 id="internal-fetch-wrapper-vs-third-party-http-client" tabindex="-1">Internal fetch wrapper vs third-party HTTP client <a class="header-anchor" href="#internal-fetch-wrapper-vs-third-party-http-client" aria-label="Permalink to &quot;Internal fetch wrapper vs third-party HTTP client&quot;">​</a></h3><p><strong>Internal fetch wrapper</strong></p><p>Pros:</p><ol><li>smaller attack surface</li><li>no additional runtime dependency</li><li>already exists in the repo</li><li>enough functionality for auth headers, JSON handling, cancellation, retries, and upload progress</li></ol><p>Cons:</p><ol><li>maintenance burden stays in-repo</li><li>some edge behavior must be tested explicitly</li></ol><p><strong>Third-party HTTP client</strong></p><p>Pros:</p><ol><li>rich feature set out of the box</li><li>familiar abstractions for many contributors</li></ol><p>Cons:</p><ol><li>adds another supply-chain dependency to solve a supply-chain problem</li><li>duplicates capabilities already present in the repo</li><li>increases transitive exposure and upgrade burden</li></ol><p>Decision:</p><ol><li>Keep the <strong>internal fetch wrapper</strong> and tighten remaining call sites around it.</li></ol><h3 id="strict-ci-only-script-blocking-vs-global-script-blocking" tabindex="-1">Strict CI-only script blocking vs global script blocking <a class="header-anchor" href="#strict-ci-only-script-blocking-vs-global-script-blocking" aria-label="Permalink to &quot;Strict CI-only script blocking vs global script blocking&quot;">​</a></h3><p><strong>CI-only blocking</strong></p><p>Pros:</p><ol><li>hardens the untrusted environment where code runs automatically</li><li>avoids surprising local development workflows</li><li>preserves normal package installation ergonomics for contributors</li></ol><p>Cons:</p><ol><li>local installs can still execute dependency scripts</li></ol><p><strong>Global blocking</strong></p><p>Pros:</p><ol><li>strongest default everywhere</li></ol><p>Cons:</p><ol><li>higher contributor surprise</li><li>more friction for common tooling workflows</li><li>likely to create ad hoc bypasses instead of clean explicit exceptions</li></ol><p>Decision:</p><ol><li>Use <strong>CI-only script blocking by default</strong> and require explicit trusted follow-up steps where needed.</li></ol><h3 id="override-only-vs-override-patch-workflow" tabindex="-1">Override-only vs override + patch workflow <a class="header-anchor" href="#override-only-vs-override-patch-workflow" aria-label="Permalink to &quot;Override-only vs override + patch workflow&quot;">​</a></h3><p><strong>Override-only</strong></p><p>Pros:</p><ol><li>simple and low-maintenance</li><li>uses built-in npm support</li></ol><p>Cons:</p><ol><li>cannot help when the vulnerable or broken code must be edited directly</li><li>blocks emergency response when no safe upstream release exists</li></ol><p><strong>Override + patch workflow</strong></p><p>Pros:</p><ol><li>supports emergency remediation without waiting on upstream</li><li>still keeps overrides as the default first-line response</li><li>can be implemented with repo-owned scripts instead of new helper packages</li></ol><p>Cons:</p><ol><li>additional documentation and process</li><li>patched dependencies require retirement discipline</li></ol><p>Decision:</p><ol><li>Use <strong>override + patch</strong>, with overrides first and patches as the documented fallback.</li></ol><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ol><li>Frontend installs become deterministic and non-scripted in CI.</li><li>Dependency changes become reviewable, attributable, and easier to audit.</li><li>Transitive vulnerability response becomes faster because overrides and patches are both available.</li><li>The app avoids adding a new HTTP client or dependency-management helper package.</li><li>Contributor guidance becomes clearer because the frontend package-manager story is singular.</li></ol><h3 id="negative-trade-offs" tabindex="-1">Negative / Trade-offs <a class="header-anchor" href="#negative-trade-offs" aria-label="Permalink to &quot;Negative / Trade-offs&quot;">​</a></h3><ol><li>CI may surface latent assumptions in packages that previously relied on lifecycle scripts.</li><li>Policy metadata adds light maintenance overhead whenever a direct dependency is added or removed.</li><li>Repo-managed patches are operationally more manual than using a dedicated patching package.</li></ol><h3 id="follow-up-constraints" tabindex="-1">Follow-up constraints <a class="header-anchor" href="#follow-up-constraints" aria-label="Permalink to &quot;Follow-up constraints&quot;">​</a></h3><ol><li>New frontend dependencies must be added to <code>frontend/dependency-policy.json</code> with an approved category and reason.</li><li>Every override and patch must include a removal condition.</li><li>Frontend release/build paths must continue to use the same hardened npm trust model instead of drifting back to unlocked installs.</li></ol>',101)])])}const g=i(t,[["render",l]]);export{u as __pageData,g as default};
